(function($){$.fn.contentslider=function(opts){var defs={easing:'swing',wrapName:'sliderWrap',frameWidth:'990px',previousText:'◄',nextText:'►',speed:832,};var opts=$.extend(defs,opts);return this.each(function(){var o=$(this);var l=o.children().size();var p=1;var aw=false;$.each(o.children(),function(i,v){$(this).css({'position':'relative','left':'0px','display':'inline','float':'left'})});o.wrap('<div style="overflow:hidden;width:'+opts.frameWidth+';" id="'+opts.wrapName+'" />').css({'width':'9999px','padding':'0'});$('#'+opts.wrapName).append('<div id="controls"><a class="next" href="">'+opts.nextText+'</a></div>');$('.prev').live('click',function(e){e.preventDefault();if(aw){return false}if(p==2){$(this).remove()}if(p==l){$('#controls').append('<a class="next" href="">'+opts.nextText+'</a>')}if(p>1){m(true);p--}});$('.next').live('click',function(e){e.preventDefault();if(aw){return false}if(p==1){$('#controls').append('<a class="prev" href="">'+opts.previousText+'</a>')}if(p==(l-1)){$(this).remove()}if(p<l){m(false);p++}});function m(d){$.each(o.children(),function(i,v){var l=(parseInt($(this).css('left')));var r=$(this).width();var w=(d)?l+r:l-r;aw=true;$(this).animate({'left':w+'px'},opts.speed,opts.easing,function(){aw=false})})}})}})(jQuery);
